  ('heelevel3-6e11b43e-moex-00042', 'heelevel3-6e11b43e', 'heelevel3-6e11b43e-moex-114-3082b5f1', 'sub-heelevel3-6e11b43e-02', NULL, 'single_choice', '下列何者屬於附負擔附款之行政處分？', '["在普通汽車駕駛執照中，附記不得操作大客車", "發給施工許可，但註記施工期間3個月", "主管機關許可舉辦演唱會，但將舉辦方所申請之4小時調整為3小時", "行政機關同意資助公務員出國進修，但進修結束後5年內不得離職"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:22+00:00", "source_pdf_sha1": "b5b55ac548cd", "answer_pdf_sha1": "940b0a4bb83c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "229", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "原住民族行政"}'::jsonb, NULL),
